    about: { title:'À propos — RelahConvert', hero_h1_1:'À propos de', hero_h1_em:'RelahConvert', hero_p:"Des outils d'image gratuits pour tous — avec la confidentialité au cœur.", s1_h:'Qui sommes-nous', s1_p1:"RelahConvert est une suite d'outils d'image gratuits, basée sur le navigateur, conçue pour quiconque a besoin de convertir, compresser ou redimensionner des images rapidement — sans télécharger de fichiers sur un serveur.", s1_p2:"Nous pensons que vos fichiers vous appartiennent. Chaque outil de RelahConvert fonctionne entièrement dans votre navigateur. Rien n'est jamais envoyé à nos serveurs.", s2_h:'Notre mission', s2_p:"Rendre les outils d'image professionnels accessibles à tous, gratuitement, sans compromis sur la confidentialité.", s3_h:'Pourquoi RelahConvert ?', s3_f1:'100 % gratuit, aucun compte requis', s3_f2:"Les fichiers ne quittent jamais votre appareil", s3_f3:'Pas de publicités, pas de suivi', s3_f4:'Fonctionne sur tous les navigateurs modernes' },
    contact: { title:'Contactez-nous — RelahConvert', hero_h1_1:'Contactez', hero_h1_em:'Nous', hero_p:"Une question, une suggestion ou un bug ? Nous serions ravis de vous entendre.", s1_h:'Nous contacter', s1_p:"Envoyez-nous un e-mail et nous vous répondrons dans 1 à 2 jours ouvrables. Pour les rapports de bugs, veuillez indiquer votre navigateur et votre système d'exploitation.", s2_h:'Ce qu\'il faut inclure', s2_p1:'Pour une réponse plus rapide, veuillez mentionner :', s2_p2:"• L'outil que vous utilisiez (ex. Compresser, JPG en PNG)<br>• Une description du problème ou de la suggestion<br>• Votre navigateur et type d'appareil (ex. Chrome sur Windows)" },
    privacy: { title:'Politique de confidentialité — RelahConvert', hero_h1_1:'Politique de', hero_h1_em:'confidentialité', updated:'Dernière mise à jour : mars 2026', s1_h:'Aucun téléchargement de fichiers', s1_p:"Tout le traitement d'images sur RelahConvert se fait localement dans votre navigateur. Vos fichiers ne sont jamais téléchargés sur nos serveurs.", s2_h:'Données que nous collectons', s2_p1:"Nous collectons des données d'utilisation anonymes minimales comme les pages vues et le type de navigateur.", s2_p2:"Nous ne collectons pas de noms, d'adresses e-mail ou d'informations personnellement identifiables.", s3_h:'Cookies', s3_p:'Nous utilisons uniquement les cookies essentiels au fonctionnement du site. Consultez notre <a href="/cookies">Politique de cookies</a>.', s4_h:'Tiers', s4_p:"Nous ne vendons, ne partageons ni ne transférons vos données à des tiers à des fins de marketing." },
    terms: { title:"Conditions d'utilisation — RelahConvert", hero_h1_1:"Conditions d'", hero_h1_em:'utilisation', updated:'Dernière mise à jour : mars 2026', s1_h:"Utilisation du service", s1_p:"RelahConvert est fourni gratuitement pour un usage personnel et commercial. Vous acceptez de ne pas utiliser le service à des fins illégales.", s2_h:'Absence de garantie', s2_p:'Le service est fourni "tel quel" sans garantie d\'aucune sorte.', s3_h:'Limitation de responsabilité', s3_p:"RelahConvert et ses opérateurs ne sont pas responsables des dommages résultant de l'utilisation du service.", s4_h:'Propriété intellectuelle', s4_p:"Le nom, le logo et le design de RelahConvert sont notre propriété intellectuelle.", s5_h:'Modifications des conditions', s5_p:"Nous nous réservons le droit de mettre à jour ces conditions à tout moment." },
    cookies: { title:'Politique de cookies — RelahConvert', hero_h1_1:'Politique de', hero_h1_em:'cookies', updated:'Dernière mise à jour : mars 2026', s1_h:'Que sont les cookies ?', s1_p:"Les cookies sont de petits fichiers texte stockés sur votre appareil lorsque vous visitez un site web.", s2_h:'Ce que nous utilisons', s2_p:"RelahConvert n'utilise que les cookies essentiels au fonctionnement de base du site.", s3_h:'Cookies tiers', s3_p:"Nous n'autorisons pas les cookies tiers sur RelahConvert.", s4_h:'Gérer les cookies', s4_p:"Vous pouvez désactiver ou effacer les cookies à tout moment dans les paramètres de votre navigateur." },
