      'jpg-to-webp':{ h2a:'Cómo convertir JPG a WebP sin subir archivos', steps:['<strong>Selecciona tus imágenes JPG</strong>.','<strong>Haz clic en Convertir</strong>.','<strong>Descarga tu WebP</strong>.'], h2b:"El mejor convertidor gratuito de JPG a WebP sin subida", body:"<p>WebP produce archivos 25–35% más pequeños que JPG con calidad visual equivalente. RelahConvert convierte JPG a WebP completamente en tu navegador.</p>", h3why:'¿Por qué convertir JPG a WebP?', why:"Los archivos WebP son 25–35% más pequeños que JPG, acelerando la carga de páginas.", faqs:[{q:'¿WebP es compatible con todos los navegadores?',a:'Sí — WebP es compatible con Chrome, Firefox, Safari y Edge.'},{q:'¿Almacenan mis imágenes?',a:'Nunca. Todo el procesamiento ocurre localmente.'}], links:[{href:'/webp-to-jpg',label:'WebP a JPG'},{href:'/jpg-to-png',label:'JPG a PNG'},{href:'/compress',label:'Comprimir'},{href:'/resize',label:'Redimensionar'}]},
