      'webp-to-png':{ h2a:'Cómo convertir WebP a PNG sin subir archivos', steps:['<strong>Selecciona tus imágenes WebP</strong>.','<strong>Haz clic en Convertir</strong>.','<strong>Descarga tu PNG</strong>.'], h2b:"El mejor convertidor gratuito de WebP a PNG sin subida", body:"<p>PNG es compatible con todos los editores de imágenes. RelahConvert convierte WebP a PNG completamente en tu navegador.</p>", h3why:'¿Por qué convertir WebP a PNG?', why:"PNG es el formato más compatible para editar imágenes WebP en cualquier software.", faqs:[{q:'¿Se preservará la transparencia del WebP en el PNG?',a:'Sí — si tu WebP tiene fondo transparente, el PNG lo conservará.'},{q:'¿Almacenan mis imágenes?',a:'Nunca. Todo el procesamiento ocurre localmente.'}], links:[{href:'/png-to-webp',label:'PNG a WebP'},{href:'/webp-to-jpg',label:'WebP a JPG'},{href:'/compress',label:'Comprimir'},{href:'/resize',label:'Redimensionar'}]},
