    about:{ title:'Über uns — RelahConvert', hero_h1_1:'Über', hero_h1_em:'RelahConvert', hero_p:'Kostenlose Bildwerkzeuge für alle — mit Datenschutz im Mittelpunkt.', s1_h:'Wer wir sind', s1_p1:'RelahConvert ist eine kostenlose, browserbasierte Bildwerkzeug-Suite für alle, die Bilder schnell konvertieren, komprimieren oder skalieren möchten — ohne Dateien auf einen Server hochzuladen.', s1_p2:'Wir glauben, dass Ihre Dateien Ihnen gehören. Jedes Tool läuft vollständig in Ihrem Browser. Nichts wird an unsere Server gesendet.', s2_h:'Unsere Mission', s2_p:'Professionelle Bildwerkzeuge kostenlos für alle zugänglich zu machen, ohne Kompromisse beim Datenschutz.', s3_h:'Warum RelahConvert?', s3_f1:'100% kostenlos, kein Konto erforderlich', s3_f2:'Dateien verlassen nie Ihr Gerät', s3_f3:'Keine Werbung, kein Tracking', s3_f4:'Funktioniert in jedem modernen Browser' },
    contact:{ title:'Kontakt — RelahConvert', hero_h1_1:'Kontakt', hero_h1_em:'', hero_p:'Haben Sie eine Frage, einen Vorschlag oder einen Fehler gefunden? Wir freuen uns von Ihnen zu hören.', s1_h:'Kontakt aufnehmen', s1_p:'Senden Sie uns eine E-Mail und wir antworten innerhalb von 1–2 Werktagen. Geben Sie bei Fehlerberichten bitte Ihren Browser und Ihr Betriebssystem an.', s2_h:'Was angeben', s2_p1:'Für eine schnellere Antwort geben Sie bitte an:', s2_p2:'• Das verwendete Tool (z.B. Komprimieren, JPG zu PNG)<br>• Eine Beschreibung des Problems oder Vorschlags<br>• Ihren Browser und Gerätetyp (z.B. Chrome auf Windows)' },
    privacy:{ title:'Datenschutzrichtlinie — RelahConvert', hero_h1_1:'Datenschutz', hero_h1_em:'richtlinie', updated:'Zuletzt aktualisiert: März 2026', s1_h:'Kein Datei-Upload', s1_p:'Die gesamte Bildverarbeitung auf RelahConvert erfolgt lokal in Ihrem Browser. Ihre Dateien werden nie auf unsere Server hochgeladen.', s2_h:'Daten, die wir erheben', s2_p1:'Wir erheben minimale anonyme Nutzungsdaten wie Seitenaufrufe und Browsertyp.', s2_p2:'Wir erheben keine Namen, E-Mail-Adressen oder personenbezogenen Daten.', s3_h:'Cookies', s3_p:'Wir verwenden nur essenzielle Cookies für die Funktionsfähigkeit der Website. Lesen Sie unsere <a href="/cookies">Cookie-Richtlinie</a>.', s4_h:'Dritte', s4_p:'Wir verkaufen, teilen oder übertragen Ihre Daten nicht an Dritte zu Marketing- oder Werbezwecken.' },
    terms:{ title:'Nutzungsbedingungen — RelahConvert', hero_h1_1:'Nutzungs', hero_h1_em:'bedingungen', updated:'Zuletzt aktualisiert: März 2026', s1_h:'Nutzung des Dienstes', s1_p:'RelahConvert wird kostenlos für den persönlichen und kommerziellen Gebrauch bereitgestellt. Sie erklären sich damit einverstanden, den Dienst nicht für rechtswidrige Zwecke zu nutzen.', s2_h:'Keine Gewährleistung', s2_p:'Der Dienst wird "wie besehen" ohne Gewährleistungen jeglicher Art bereitgestellt.', s3_h:'Haftungsbeschränkung', s3_p:'RelahConvert und seine Betreiber haften nicht für Schäden, die aus der Nutzung des Dienstes entstehen.', s4_h:'Geistiges Eigentum', s4_p:'Der Name, das Logo und das Design von RelahConvert sind unser geistiges Eigentum.', s5_h:'Änderungen der Bedingungen', s5_p:'Wir behalten uns das Recht vor, diese Bedingungen jederzeit zu aktualisieren.' },
    cookies:{ title:'Cookie-Richtlinie — RelahConvert', hero_h1_1:'Cookie', hero_h1_em:'Richtlinie', updated:'Zuletzt aktualisiert: März 2026', s1_h:'Was sind Cookies?', s1_p:'Cookies sind kleine Textdateien, die auf Ihrem Gerät gespeichert werden, wenn Sie eine Website besuchen.', s2_h:'Was wir verwenden', s2_p:'RelahConvert verwendet nur essenzielle Cookies für die grundlegende Funktionsfähigkeit der Website.', s3_h:'Drittanbieter-Cookies', s3_p:'Wir erlauben keine Drittanbieter-Cookies auf RelahConvert.', s4_h:'Cookies verwalten', s4_p:'Sie können Cookies jederzeit über Ihre Browsereinstellungen deaktivieren oder löschen.' },
